import { useState, useEffect } from 'react'
import { useNavigate, useLocation } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import { useFoodLog } from '../hooks/useFoodLog'
import { useWaterLog } from '../hooks/useWaterLog'
import { useWeightLog } from '../hooks/useWeightLog'
import StockTicker from '../components/StockTicker'

const CAR_IMG = 'data:image/jpeg;base64,'

import { usePrayers } from '../hooks/usePrayers'
import { useToday } from '../hooks/useToday'
import { useStreaks } from '../hooks/useStreaks'
import LineChart from '../components/LineChart'
import { supabase } from '../lib/supabase'



const CALORIE_GOAL = 2200
const WATER_GOAL   = 8

function getGreeting() {
  const h = new Date().getHours()
  if (h < 12) return 'Good Morning'
  if (h < 17) return 'Good Afternoon'
  return 'Good Evening'
}

const Ico = {
  food:     (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 2v7c0 1.1.9 2 2 2h4a2 2 0 0 0 2-2V2"/><path d="M7 2v20"/><path d="M21 15V2a5 5 0 0 0-5 5v6c0 1.1.9 2 2 2h3Zm0 0v7"/></svg>,
  water:    (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M9 2h6"/><path d="M7.5 5h9l.5 2V20a2 2 0 0 1-2 2h-5a2 2 0 0 1-2-2V7l.5-2z"/><path d="M7.5 11h9"/></svg>,
  weight:   (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="5" r="3"/><path d="M6.5 8a2 2 0 0 0-1.905 1.46L2.1 18.5A2 2 0 0 0 4 21h16a2 2 0 0 0 1.925-2.54L19.4 9.5A2 2 0 0 0 17.48 8Z"/></svg>,
  prayer:   (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="3" x2="12" y2="21"/><line x1="5" y1="8.5" x2="19" y2="8.5"/></svg>,
  book:     (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>,
  fitness:  (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect x="1.5" y="9" width="4" height="6" rx="1.5"/><rect x="6" y="10.5" width="2" height="3" rx="0.6"/><line x1="8" y1="12" x2="16" y2="12" strokeWidth="2.5"/><rect x="16" y="10.5" width="2" height="3" rx="0.6"/><rect x="18.5" y="9" width="4" height="6" rx="1.5"/></svg>,
  settings: (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>,
  home:     (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>,
  plus:     (s=16) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>,
  chevron:  (s=14) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18l6-6-6-6"/></svg>,
  finance:  (s=18) => <svg width={s} height={s} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="6" width="20" height="12" rx="2"/><circle cx="12" cy="12" r="2"/><path d="M6 10v4M18 10v4"/></svg>,
}

const MODULE_COLORS = {
  food:       '#c8d4c8', // lettuce green
  water:      '#9ab4cc', // sky blue
  prayer:     '#c8a000', // dark gold
  devotional: '#a8b4c0', // red
  fitness:    '#b4bccc', // dark blue
  finance:    '#b4c4b0', // money green
}

const modules = [
  { key:'food',       label:'Food Journal', path:'/food',       icon: Ico.food },
  { key:'water',      label:'Water',        path:'/water',      icon: Ico.water },
  { key:'prayer',     label:'Prayer',       path:'/prayer',     icon: Ico.prayer },
  { key:'devotional', label:'Devotional',   path:'/devotional', icon: Ico.book },
  { key:'fitness',    label:'Fitness Center', path:'/fitness',    icon: Ico.fitness },
  { key:'finance',    label:'Finance',      path:'/finance',    icon: Ico.finance },
]

function GlowBar({ pct, h = 3, color = 'var(--btn-bg)', glow = 'rgba(212,212,232,0.55)' }) {
  return (
    <div style={{ width:'100%', height:h, borderRadius:99, background:'rgba(212,212,232,0.07)', overflow:'hidden' }}>
      <div style={{ height:'100%', width:`${pct}%`, background:color, borderRadius:99, transition:'width 0.9s cubic-bezier(.16,1,.3,1)', boxShadow:`0 0 8px ${glow}` }} />
    </div>
  )
}

function Card({ children, style={} }) {
  return (
    <div style={{ background:'var(--bg-card)', border:'1px solid var(--border)', boxShadow:'var(--card-shadow)', borderRadius:14, padding:'18px 16px', ...style }}>
      {children}
    </div>
  )
}

function SectionHead({ title, action, actionLabel, color }) {
  const c = color || 'rgba(212,212,232,0.8)'
  return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:14 }}>
      <div style={{ display:'flex', alignItems:'center', gap:9 }}>
        <div style={{ width:2, height:14, background:`linear-gradient(to bottom,${c},${c}22)`, borderRadius:2, boxShadow:`0 0 6px ${c}88` }} />
        <p style={{ color: color || 'var(--text-secondary)', fontSize:10, letterSpacing:'0.26em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', fontWeight:700 }}>{title}</p>
      </div>
      {action && <button onClick={action} style={{ background:'none', border:'none', cursor:'pointer', color: color ? `${color}99` : 'var(--text-muted)', fontSize:11, fontFamily:'Helvetica Neue,sans-serif' }}>{actionLabel}</button>}
    </div>
  )
}

export function BottomNav() {
  const navigate = useNavigate()
  const loc = useLocation()
  const items = [
    { label:'Home',      path:'/dashboard',  icon: Ico.home,    color: '#d8d8e8' },
    { label:'Food',      path:'/food',       icon: Ico.food,    color: '#c8d4c8' },
    { label:'Water',     path:'/water',      icon: Ico.water,   color: '#9ab4cc' },
    { label:'Fitness',   path:'/fitness',    icon: Ico.fitness, color: '#b4bccc' },
    { label:'Prayer',    path:'/prayer',     icon: Ico.prayer,  color: '#c8a000' },
    { label:'Devotion',  path:'/devotional', icon: Ico.book,    color: '#a8b4c0' },
    { label:'Finance',   path:'/finance',    icon: Ico.finance, color: '#b4c4b0' },
    { label:'Settings',  path:'/settings',   icon: Ico.settings,color: '#7a7a8a' },
  ]
  return (
    <nav style={{
      position:'fixed', bottom:0, left:0, right:0, zIndex:100,
      background:'var(--header-bg)', backdropFilter:'blur(20px)', WebkitBackdropFilter:'blur(20px)',
      borderTop:'1px solid var(--border)',
      display:'flex', alignItems:'center', justifyContent:'space-around',
      padding:'10px 0 max(12px,env(safe-area-inset-bottom))',
    }}>
      {items.map(({ label, path, icon, color }) => {
        const active = loc.pathname === path
        return (
          <button key={path} onClick={() => navigate(path)} style={{
            display:'flex', flexDirection:'column', alignItems:'center', gap:4,
            background:'none', border:'none', cursor:'pointer',
            opacity: active ? 1 : 0.45,
            transition:'opacity 0.2s',
            minWidth:52, padding:'2px 0',
          }}>
            <div style={{ color, filter: active ? `drop-shadow(0 0 6px ${color}bb)` : 'none', transition:'filter 0.2s' }}>
              {icon(22)}
            </div>
            <span style={{ color, fontSize:9, letterSpacing:'0.08em', fontFamily:'Helvetica Neue,sans-serif', fontWeight: active ? 700 : 400 }}>{label}</span>
          </button>
        )
      })}
    </nav>
  )
}

export default function Dashboard() {
  const todayStr = useToday()
  const streaks  = useStreaks()
  const dayName  = new Date(todayStr + 'T00:00:00').toLocaleDateString('en-US', { weekday: 'long' })
  const dateStr  = new Date(todayStr + 'T00:00:00').toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
  const navigate = useNavigate()
  const { user }  = useAuth()
  const [profile, setProfile] = useState(null)
  const [visible, setVisible] = useState(false)

  const { totals, logs: foodLogs } = useFoodLog(todayStr)
  const { count: waterCount }      = useWaterLog(todayStr)
  const { latest, goal: weightGoal } = useWeightLog()
  const { prayers }                = usePrayers()

  useEffect(() => {
    if (!user) return
    supabase.from('profiles').select('name').eq('id', user.id).single()
      .then(({ data }) => { if (data) setProfile(data) })
    const t = setTimeout(() => setVisible(true), 60)
    return () => clearTimeout(t)
  }, [user])

  const displayName   = profile?.name || 'Ethan'
  const calories      = totals?.calories || 0
  const calPct        = Math.min(100, Math.round((calories / CALORIE_GOAL) * 100))
  const waterPct      = Math.min(100, Math.round((waterCount / WATER_GOAL) * 100))
  const calLeft       = Math.max(0, CALORIE_GOAL - calories)
  const todayPrayers  = (prayers || []).filter(p => p.date === todayStr).length
  const answeredCount = (prayers || []).filter(p => p.answered).length

  const loggedModules = {
    food:       calories > 0,
    water:      waterCount > 0,
    prayer:     todayPrayers > 0,
    devotional: false,
    fitness:    false,
  }
  const loggedCount = Object.values(loggedModules).filter(Boolean).length
  const recentFood  = (foodLogs || []).slice(-3).reverse()

  const anim = (delay = 0) => ({
    opacity: visible ? 1 : 0,
    transform: visible ? 'translateY(0)' : 'translateY(14px)',
    transition: `opacity 0.5s ease ${delay}ms, transform 0.5s ease ${delay}ms`,
  })

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital@1&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        body{background:var(--bg-primary);overflow-x:hidden;}
        ::-webkit-scrollbar{width:3px;}
        ::-webkit-scrollbar-thumb{background:rgba(212,212,232,0.1);border-radius:99px;}
        .ax-pill:hover{background:rgba(212,212,232,0.06)!important;border-color:rgba(212,212,232,0.18)!important;}
        .ax-log-row:hover{background:rgba(212,212,232,0.03);border-radius:8px;}
        .ax-btn-white:hover{background:rgba(212,212,232,0.88)!important;box-shadow:0 0 22px rgba(212,212,232,0.22)!important;}
      `}</style>

      <div style={{ minHeight:'100vh', background:'var(--bg-primary)', WebkitFontSmoothing:'antialiased', paddingBottom:90, position:'relative' }}>
        {/* Car background */}
        <div style={{
          position:'fixed', inset:0, zIndex:0,
          backgroundImage:`url(${CAR_IMG})`,
          backgroundSize:'cover', backgroundPosition:'center 40%',
          backgroundRepeat:'no-repeat',
          opacity:0.1,
          pointerEvents:'none',
          filter:'grayscale(100%)',
        }} />
        <div style={{
          position:'fixed', inset:0, zIndex:0,
          background:'linear-gradient(to bottom, rgba(8,8,8,0.5) 0%, rgba(8,8,8,0.2) 40%, rgba(8,8,8,0.85) 100%)',
          pointerEvents:'none',
        }} />

        {/* Sticky Header */}
        <div style={{
          position:'sticky', top:0, zIndex:50,
          background:'var(--header-bg)', backdropFilter:'blur(18px)', WebkitBackdropFilter:'blur(18px)',
          borderBottom:'1px solid var(--border)',
          padding:'14px 16px 12px',
        }}>
          <p style={{ color:'var(--text-muted)', fontSize:10, letterSpacing:'0.26em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', marginBottom:6 }}>
            {dayName} · {dateStr}
          </p>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10 }}>
            <h1 style={{ color:'var(--text-primary)', fontWeight:900, fontSize:21, fontFamily:'Helvetica Neue,sans-serif', letterSpacing:'-0.02em', lineHeight:1.15 }}>
              {getGreeting()},{' '}
              <span style={{ fontStyle:'italic', fontFamily:"'EB Garamond',serif", fontWeight:400, fontSize:23 }}>{displayName}.</span>
            </h1>
            <button onClick={() => navigate('/food')} className="ax-btn-white"
              style={{ background:'var(--btn-bg)', color:'var(--bg-primary)', border:'none', borderRadius:9, padding:'9px 14px', fontSize:11, fontWeight:800, letterSpacing:'0.14em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', cursor:'pointer', whiteSpace:'nowrap', flexShrink:0, transition:'background 0.2s,box-shadow 0.2s', display:'flex', alignItems:'center', gap:5 }}>
              {Ico.plus(12)} Log
            </button>
          </div>
        </div>

        {/* Stock Ticker */}
        <StockTicker />

        {/* Scrollable body */}
        <div style={{ padding:'16px 16px 0', display:'flex', flexDirection:'column', gap:14, maxWidth:600, margin:'0 auto', position:'relative', zIndex:1 }}>

          {/* 2×2 Stat Grid */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10, ...anim(60) }}>
            {[
              { label:'Calories', value: calories.toLocaleString(), sub:`of ${CALORIE_GOAL.toLocaleString()} goal`, pct: calPct,  color:'#b8b0c8', path:'/food' },
              { label:'Water',    value:`${waterCount} / ${WATER_GOAL}`, sub:'glasses today', pct: waterPct,                     color:'#9ab4cc', path:'/water' },
              { label:'Weight',   value: latest ? `${latest} lb` : '—', sub: latest && weightGoal ? `${Math.max(0,latest-weightGoal).toFixed(1)} lb from goal` : 'not logged', pct: null, color:'#b8b8cc', path:'/fitness' },
              { label:'Today',    value:`${loggedCount} / 5`, sub:'modules logged', pct: Math.round((loggedCount/5)*100),        color:'#d8d8e8' },
            ].map(({ label, value, sub, pct, color, path }) => (
              <div key={label} onClick={path ? () => navigate(path) : undefined} style={{ background:'var(--bg-card)', border:`1px solid ${color}33`, boxShadow:`var(--card-shadow), 0 0 12px ${color}11`, borderRadius:14, padding:'14px', position:'relative', overflow:'hidden', cursor: path ? 'pointer' : 'default' }}>
                <div style={{ position:'absolute', top:0, right:0, width:50, height:50, background:`radial-gradient(circle at top right,${color}18,transparent 70%)`, pointerEvents:'none' }} />
                <p style={{ color:`${color}99`, fontSize:9, letterSpacing:'0.24em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', marginBottom:6 }}>{label}</p>
                <p style={{ color, fontSize:24, fontWeight:900, fontFamily:'Helvetica Neue,sans-serif', lineHeight:1, marginBottom:4 }}>{value}</p>
                <p style={{ color:'var(--text-muted)', fontSize:11, fontFamily:'Helvetica Neue,sans-serif', marginBottom: pct != null ? 10 : 0 }}>{sub}</p>
                {pct != null && <GlowBar pct={pct} color={color} glow={`${color}66`} />}
              </div>
            ))}
          </div>

          {/* Modules */}
          <Card style={anim(160)}>
            <SectionHead title="Today's Modules" actionLabel={`${loggedCount} of 5`} />
            <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
              {modules.map(({ key, label, path, icon }, i) => {
                const done  = loggedModules[key]
                const color = MODULE_COLORS[key] || 'rgba(212,212,232,0.5)'
                return (
                  <button key={key} onClick={() => navigate(path)} className="ax-pill"
                    style={{
                      display:'flex', alignItems:'center', justifyContent:'space-between',
                      padding:'13px 14px', borderRadius:11,
                      border:`1px solid ${done ? `${color}30` : 'rgba(212,212,232,0.06)'}`,
                      background: done ? `${color}0d` : 'rgba(212,212,232,0.02)',
                      cursor:'pointer', textAlign:'left', width:'100%',
                      opacity: visible ? 1 : 0,
                      transform: visible ? 'translateX(0)' : 'translateX(-8px)',
                      transition: `opacity 0.4s ease ${200 + i*45}ms, transform 0.4s ease ${200 + i*45}ms, background 0.2s, border-color 0.2s`,
                    }}>
                    <div style={{ display:'flex', alignItems:'center', gap:12 }}>
                      <div style={{ width:7, height:7, borderRadius:'50%', background: done ? color : `${color}55`, boxShadow: done ? `0 0 7px ${color}99` : 'none', flexShrink:0 }} />
                      <div style={{ color: done ? color : `${color}66` }}>{icon(15)}</div>
                      <div>
                        <p style={{ color: done ? color : `${color}cc`, fontSize:13, fontWeight:600, fontFamily:'Helvetica Neue,sans-serif', marginBottom:1 }}>{label}</p>
                        <p style={{ color: done ? `${color}88` : `${color}55`, fontSize:11, fontFamily:'Helvetica Neue,sans-serif' }}>{done ? 'Logged' : 'Pending'}</p>
                      </div>
                    </div>
                    <div style={{ color:'rgba(212,212,232,0.2)' }}>{Ico.chevron()}</div>
                  </button>
                )
              })}
            </div>
          </Card>

          {/* Food */}
          <Card style={anim(280)}>
            <SectionHead title="Recent Food Log" action={() => navigate('/food')} actionLabel="View all →" color={MODULE_COLORS.food} />
            {recentFood.length === 0
              ? <p style={{ color:'rgba(212,212,232,0.2)', fontSize:13, fontStyle:'italic', fontFamily:'Helvetica Neue,sans-serif', textAlign:'center', padding:'14px 0' }}>Nothing logged yet today.</p>
              : recentFood.map((e, i) => (
                <div key={e.id} className="ax-log-row" style={{ display:'flex', justifyContent:'space-between', padding:'10px 6px', borderBottom: i < recentFood.length-1 ? '1px solid rgba(212,212,232,0.05)' : 'none', transition:'background 0.15s' }}>
                  <span style={{ color:'rgba(212,212,232,0.7)', fontSize:13, fontFamily:'Helvetica Neue,sans-serif' }}>{e.food_name}</span>
                  <span style={{ color:`${MODULE_COLORS.food}88`, fontSize:13, fontFamily:'Helvetica Neue,sans-serif' }}>{e.calories} cal</span>
                </div>
              ))
            }
            <div style={{ marginTop:14, paddingTop:14, borderTop:'1px solid rgba(212,212,232,0.06)', display:'flex', alignItems:'center', gap:14 }}>
              <div>
                <p style={{ color:`${MODULE_COLORS.food}88`, fontSize:9, letterSpacing:'0.2em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', marginBottom:4 }}>Remaining</p>
                <p style={{ color:MODULE_COLORS.food, fontWeight:900, fontSize:16, fontFamily:'Helvetica Neue,sans-serif' }}>{calLeft.toLocaleString()} cal</p>
              </div>
              <div style={{ flex:1 }}>
                <GlowBar pct={calPct} h={4} color={MODULE_COLORS.food} glow="rgba(200,212,200,0.5)" />
                <p style={{ color:`${MODULE_COLORS.food}99`, fontSize:10, textAlign:'right', marginTop:5, fontFamily:'Helvetica Neue,sans-serif' }}>{calPct}%</p>
              </div>
            </div>
          </Card>

          {/* Water */}
          <Card style={anim(340)}>
            <SectionHead title="Water Intake" action={() => navigate('/water')} actionLabel="Open →" color={MODULE_COLORS.water} />
            <div style={{ display:'flex', flexWrap:'wrap', gap:8, marginBottom:12 }}>
              {Array.from({ length: WATER_GOAL }).map((_,i) => {
                const full = i < waterCount
                return (
                  <svg key={i} width={26} height={26} viewBox="0 0 24 24" fill="none" strokeLinecap="round" strokeLinejoin="round" style={{ transition:'all 0.3s', filter: full ? '0 0 6px rgba(154,180,204,0.5)' : 'none' }}>
                    <path d="M6 5 L9 20 C9.2 21.1 10.1 22 11.1 22 L12.9 22 C13.9 22 14.8 21.1 15 20 L18 5 Z" fill={full ? 'rgba(154,180,204,0.7)' : 'rgba(212,212,232,0.04)'} stroke="none"/>
                    <path d="M5 3 L9 20 C9.2 21.1 10.1 22 11.1 22 L12.9 22 C13.9 22 14.8 21.1 15 20 L19 3" stroke={full ? '#9ab4cc' : 'rgba(212,212,232,0.18)'} strokeWidth="1.4"/>
                    <line x1="5" y1="3" x2="19" y2="3" stroke={full ? '#9ab4cc' : 'rgba(212,212,232,0.18)'} strokeWidth="1.4"/>
                    <path d="M19 8 C21.5 8 21.5 13 19 13" stroke={full ? '#9ab4cc' : 'rgba(212,212,232,0.18)'} strokeWidth="1.4"/>
                  </svg>
                )
              })}
            </div>
            <p style={{ color: waterCount >= WATER_GOAL ? '#9ab4cc' : 'var(--text-muted)', fontSize:12, fontFamily:'Helvetica Neue,sans-serif', marginBottom:10 }}>
              {waterCount >= WATER_GOAL ? '✓ Goal reached — well done.' : `${WATER_GOAL - waterCount} glass${WATER_GOAL - waterCount !== 1 ? 'es' : ''} remaining`}
            </p>
            <GlowBar pct={waterPct} color={MODULE_COLORS.water} glow="rgba(154,180,204,0.5)" />
          </Card>

          {/* Prayer */}
          <Card style={anim(400)}>
            <SectionHead title="Prayer" action={() => navigate('/prayer')} actionLabel="Open →" color={MODULE_COLORS.prayer} />
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10, marginBottom:14 }}>
              {[{ label:'Today', value: todayPrayers, sub:'logged' },{ label:'Answered', value: answeredCount, sub:'total' }].map(({ label, value, sub }) => (
                <div key={label} style={{ background:'var(--stat-bg)', border:`1px solid ${MODULE_COLORS.prayer}22`, boxShadow:'var(--card-shadow)', borderRadius:10, padding:'13px 14px' }}>
                  <p style={{ color:'var(--text-muted)', fontSize:9, letterSpacing:'0.22em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', marginBottom:6 }}>{label}</p>
                  <p style={{ color:MODULE_COLORS.prayer, fontSize:26, fontWeight:900, fontFamily:'Helvetica Neue,sans-serif', lineHeight:1, marginBottom:4 }}>{value}</p>
                  <p style={{ color:'var(--text-muted)', fontSize:11, fontFamily:'Helvetica Neue,sans-serif' }}>{sub}</p>
                </div>
              ))}
            </div>
            <button onClick={() => navigate('/prayer')}
              style={{ width:'100%', padding:'11px', borderRadius:8, background:'transparent', border:`1px solid ${MODULE_COLORS.prayer}44`, color:`${MODULE_COLORS.prayer}99`, fontSize:11, letterSpacing:'0.18em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', fontWeight:700, cursor:'pointer', transition:'border-color 0.2s,color 0.2s' }}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=MODULE_COLORS.prayer;e.currentTarget.style.color=MODULE_COLORS.prayer}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=`${MODULE_COLORS.prayer}44`;e.currentTarget.style.color=`${MODULE_COLORS.prayer}99`}}
            >
              + Log a prayer
            </button>
          </Card>

        </div>
      </div>


        {/* Streaks */}
        <div style={{ padding:'0 16px 100px' }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:12 }}>
            <p style={{ color:'var(--text-primary)', fontSize:12, fontWeight:700, letterSpacing:'0.18em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif' }}>Streaks</p>
            <p style={{ color:'var(--text-muted)', fontSize:10, fontFamily:'Helvetica Neue,sans-serif', fontStyle:'italic' }}>consecutive days</p>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(5,1fr)', gap:8 }}>
            {[
              { label:'Food',    val: streaks.food,       color: MODULE_COLORS.food       },
              { label:'Water',   val: streaks.water,      color: MODULE_COLORS.water      },
              { label:'Fitness', val: streaks.fitness,    color: MODULE_COLORS.fitness    },
              { label:'Prayer',  val: streaks.prayer,     color: MODULE_COLORS.prayer     },
              { label:'Devot.',  val: streaks.devotional, color: MODULE_COLORS.devotional },
            ].map(({ label, val, color }) => (
              <div key={label} style={{ background:`${color}11`, border:`1px solid ${color}44`, boxShadow:`0 0 10px ${color}22`, borderRadius:10, padding:'10px 6px', textAlign:'center' }}>
                <p style={{ color, fontSize:20, fontWeight:900, fontFamily:'Helvetica Neue,sans-serif', letterSpacing:'-0.02em', lineHeight:1 }}>{val}</p>
                <p style={{ color:`${color}99`, fontSize:9, letterSpacing:'0.12em', textTransform:'uppercase', fontFamily:'Helvetica Neue,sans-serif', marginTop:4 }}>{label}</p>
                {val >= 1 && (
                  <p style={{ fontSize:11, marginTop:3 }}>
                    {val >= 7 ? '🔥🔥 ×2' : '🔥 ×1'}
                  </p>
                )}
              </div>
            ))}
          </div>
        </div>
      <BottomNav />
    </>
  )
}
